 "CASR":   "P41180",
 "HCAR1":  "Q9BXC0",
 "GPRC6A": "Q5T6X5",
 "NPY1R":  "P25929",
 "MC4R":   "P32245",
 "TAS1R1": "Q7RTX1",
 "TAS1R3": "Q7RTX0",
 "GPR171": "O14626",
 "MRGPRD": "Q8TDS7",
 "OR51E1": "Q8TCB6",
}

def pdbs_for_uniprot(acc):
    q = {
      "query": {
        "type":"terminal","service":"text",
        "parameters":{
          "attribute":"rcsb_polymer_entity_container_identifiers.reference_sequence_identifiers.database_accession",
          "operator":"exact_match","value":acc}
      },
      "return_type":"polymer_entity",
      "request_options":{"return_all_hits":True}
    }
    r = requests.get("https://search.rcsb.org/rcsbsearch/v2/query",
                     params={"json":json.dumps(q)}, timeout=30)
    if r.status_code!=200:
        return []
    d = r.json()
    return [x["identifier"] for x in d.get("result_set",[])]

out={}
for name,acc in receptors.items():
    try:
        hits = pdbs_for_uniprot(acc)
    except Exception as e:
        hits = f"ERR {e}"
    out[name]=hits
    print(f"{name:8s} {acc}: {len(hits) if isinstance(hits,list) else hits} -> {hits[:12] if isinstance(hits,list) else ''}")

for name,acc in af.items():
    r=requests.get(f"https://rest.uniprot.org/uniprotkb/{acc}.json",timeout=30)
    if r.status_code==200:
        d=r.json()
        prim=d.get("primaryAccession")
        secs=d.get("secondaryAccessions",[])
        print(name, "given",acc,"-> primary",prim, "secondary",secs[:5])
    else:
        # maybe it's a secondary - search
        print(name, acc, "status", r.status_code)

for name,acc in af.items():
    r=requests.get(f"https://alphafold.ebi.ac.uk/api/prediction/{acc}",timeout=30)
    print(name, acc, r.status_code)
    if r.status_code==200:
        d=r.json()
        if d:
            print("   pdbUrl:", d[0].get("pdbUrl"))
    else:
        print("   body:", r.text[:150])

