import numpy as np, glob

def pocket_centers(t, npock=4):
    # parse pocket alpha spheres from pockets/pocketN_atm.pdb (STP atoms)
    res={}
    pdir=f"dock/receptors/{t}_rec_out/pockets"
    for f in sorted(glob.glob(f"{pdir}/pocket*_vert.pqr")):
        pid=int(f.split("pocket")[1].split("_")[0])
        if pid>npock: continue
        c=[]
        for l in open(f):
            if l.startswith(("ATOM","HETATM")):
                c.append((float(l[30:38]),float(l[38:46]),float(l[46:54])))
        if c: res[pid]=np.array(c)
    return res

def rec_centroid(t):
    c=[]
    for l in open(f"dock/receptors/{t}_rec.pdb"):
        if l.startswith("ATOM") and l[12:16].strip()=="CA":
            c.append((float(l[30:38]),float(l[38:46]),float(l[46:54])))
    return np.array(c)

for t in ["TAS1R3","GPRC6A","TAS1R1","GPR171","OR51E1"]:
    ca=rec_centroid(t)
    cen=ca.mean(0)
    zc=ca[:,2]
    pk=pocket_centers(t)
    print(f"=== {t}: CA centroid={cen.round(1)}, z-range=[{zc.min():.0f},{zc.max():.0f}] nres={len(ca)}")
    for pid,arr in pk.items():
        pc=arr.mean(0)
        # distance from centroid, count CA within 8A (buriedness proxy)
        d=np.linalg.norm(ca-pc,axis=1)
        near=(d<10).sum()
        print(f"   pocket {pid}: center={pc.round(1)} |from_centroid|={np.linalg.norm(pc-cen):.1f} CA_within10A={near}")

import os
def pocket_centers(t, npock=4):
    res={}
    pdir=f"dock/receptors/{t}_rec_out/pockets"
    for fn in sorted(os.listdir(pdir)):
        if not (fn.startswith("pocket") and fn.endswith("_vert.pqr")): continue
        pid=int(fn[len("pocket"):].split("_")[0])
        if pid>npock: continue
        c=[]
        for l in open(os.path.join(pdir,fn)):
            if l.startswith(("ATOM","HETATM")):
                c.append((float(l[30:38]),float(l[38:46]),float(l[46:54])))
        if c: res[pid]=np.array(c)
    return res

af_box={}
for t in ["TAS1R3","GPRC6A","TAS1R1","GPR171","OR51E1"]:
    ca=rec_centroid(t); cen=ca.mean(0); zc=ca[:,2]
    pk=pocket_centers(t)
    print(f"=== {t}: centroid={cen.round(1)} z=[{zc.min():.0f},{zc.max():.0f}] nres={len(ca)}")
    for pid,arr in sorted(pk.items()):
        pc=arr.mean(0); near=(np.linalg.norm(ca-pc,axis=1)<10).sum()
        print(f"   pk{pid}: center={pc.round(1)} nsph={len(arr)} |dcen|={np.linalg.norm(pc-cen):.1f} CA<10A={near}")

import re
def drugg_scores(t):
