import json
json.dump(box_info, open("handoff/box_info.json","w"), indent=1)
print("\nAll boxes:", list(box_info.keys()))

import numpy as np
from collections import defaultdict

# --- refined pharmacophore-contact detection ---
BASIC_ATOMS={"ARG":["NH1","NH2","NE","CZ"],"LYS":["NZ"],"HIS":["ND1","NE2"]}
AROM_RES={"PHE","TYR","TRP","HIS"}
AROM_RING_ATOMS={"PHE":["CG","CD1","CD2","CE1","CE2","CZ"],
                 "TYR":["CG","CD1","CD2","CE1","CE2","CZ"],
                 "TRP":["CG","CD1","CD2","NE1","CE2","CE3","CZ2","CZ3","CH2"],
                 "HIS":["CG","ND1","CD2","CE1","NE2"]}
# receptor H-bond capable heavy atoms (N,O adtypes in pdbqt: N,NA,OA + backbone)
def rec_atom_records(t):
    recs=[]
    for l in open(f"dock/receptors/{t}_rec.pdbqt"):
        if l.startswith(("ATOM","HETATM")):
            rn=l[17:20].strip(); rs=l[22:27].strip(); ch=l[21]; an=l[12:16].strip()
            ad=l[77:79].strip()
            x,y,z=float(l[30:38]),float(l[38:46]),float(l[46:54])
            recs.append(dict(rn=rn,rs=rs,ch=ch,an=an,ad=ad,xyz=np.array([x,y,z])))
    return recs

def lig_atom_records(pose_atoms):
    return [dict(an=a[0],ad=a[1],xyz=np.array(a[2:5])) for a in pose_atoms]

def classify_pharmacophore(t, pose_atoms):
    """Detect: salt-bridge partner residue, lactoyl/hydroxyl H-bond partners, pi-stack aromatic residue.
       Returns dict with residue identifiers."""
    rec=rec_atom_records(t)
    lig=lig_atom_records(pose_atoms)
    # ligand carboxylate O atoms (OA), lactoyl OH (OA bonded to sp3 - approximate: OA not in carboxylate)
    lig_OA=[a for a in lig if a["ad"]=="OA"]
    lig_N =[a for a in lig if a["ad"] in ("N","NA","HD")]  # amide N / donors
    # aromatic ring centroid of ligand phenyl: ligand carbons in a ring — approx use all aromatic A-type carbons
    lig_A =[a for a in lig if a["ad"]=="A"]  # aromatic carbons
    ring_cen = np.mean([a["xyz"] for a in lig_A],axis=0) if len(lig_A)>=5 else None

    res_out={"saltbridge":None,"hbond_res":set(),"pistack":None,"contact_res":set()}
    # salt bridge: any ligand OA within 4.5A of a basic-residue N
    best_sb=None
    for a in lig_OA:
        for r in rec:
            if r["rn"] in BASIC_ATOMS and r["an"] in BASIC_ATOMS[r["rn"]] and r["an"].startswith(("N",)):
                d=np.linalg.norm(a["xyz"]-r["xyz"])
                if d<4.5:
                    key=(r["rn"],r["rs"],r["ch"])
                    if best_sb is None or d<best_sb[1]: best_sb=(key,d)
    if best_sb: res_out["saltbridge"]=best_sb[0]
    # H-bonds: ligand OA/donor within 3.5A of receptor N/O heavy atom
    for a in lig_OA + [x for x in lig if x["ad"]=="OA"]:
        for r in rec:
            if r["ad"] in ("N","NA","OA") or r["an"] in ("O","N","OG","OG1","OH","OD1","OD2","OE1","OE2","ND1","ND2","NE2","NE","NH1","NH2","NZ","SG"):
                d=np.linalg.norm(a["xyz"]-r["xyz"])
                if d<3.5:
                    res_out["hbond_res"].add((r["rn"],r["rs"],r["ch"]))
    # pi-stack: ligand ring centroid within 6A of aromatic residue ring centroid
    if ring_cen is not None:
        byres=defaultdict(list)
        for r in rec:
            if r["rn"] in AROM_RING_ATOMS and r["an"] in AROM_RING_ATOMS[r["rn"]]:
                byres[(r["rn"],r["rs"],r["ch"])].append(r["xyz"])
        best_pi=None
        for key,atoms in byres.items():
            if len(atoms)>=4:
                cen=np.mean(atoms,axis=0); d=np.linalg.norm(ring_cen-cen)
                if d<6.0 and (best_pi is None or d<best_pi[1]): best_pi=(key,d)
        if best_pi: res_out["pistack"]=best_pi[0]
    # all contact residues (any lig atom within 4.0A)
    lc=np.array([a["xyz"] for a in lig])
    for r in rec:
        if (np.linalg.norm(lc-r["xyz"],axis=1)<4.0).any():
            res_out["contact_res"].add((r["rn"],r["rs"],r["ch"]))
    return res_out, ring_cen

print("pharmacophore classifier ready")

def pose_centroid(pose_atoms):
    return np.mean([a[2:5] for a in pose_atoms],axis=0)

def all_lig_coords(pose_atoms):
    return np.array([a[2:5] for a in pose_atoms])

# reference: parent top pose per receptor
parent_ref={}
for t in RECS:
    poses=parse_poses(t,"parent")
    top=poses[0]  # smina orders best first
    ph,ring=classify_pharmacophore(t, top[1])
    parent_ref[t]=dict(score=top[0], atoms=top[1], centroid=pose_centroid(top[1]),
                       ph=ph, ring=ring)
    sb=ph["saltbridge"]; pi=ph["pistack"]
    print(f"{t}: parent {top[0]} kcal | saltbridge={sb} | pistack={pi} | #hbond_res={len(ph['hbond_res'])} | #contacts={len(ph['contact_res'])}")

# Prepare overlay data for figure: for 3 representative high-confidence targets,
# extract parent top pose + best analog poses (heavy-atom coords) and key residue CA positions.
import numpy as np, json

def heavy_coords(pose_atoms):
    return np.array([a[2:5] for a in pose_atoms if not a[0].startswith("H") and a[1]!="HD"])

def full_coords(pose_atoms):
    return np.array([a[2:5] for a in pose_atoms])

fig_targets=["HCAR1","MRGPRD","NPY1R"]
overlay={}
for t in fig_targets:
    ref=parent_ref[t]
    pcoords=full_coords(ref["atoms"])
    # analogs to overlay (best consistency pose we scored) - re-derive best pose coords
    entries={"parent":pcoords}
    # pick 2 representative analogs: one high-consistency, one divergent
    subt=consdf[(consdf.target==t)&(consdf.analog!="parent")].sort_values("consistency",ascending=False)
    picks=[subt.iloc[0].analog, subt.iloc[-1].analog]
    for lg in picks:
        # find the best-consistency pose again
        b=score_analog(t,lg)
        # need its atoms: re-run to get atoms
        poses=parse_poses(t,lg)
        # recompute to match best
        best_atoms=None; best_c=-1
        for score,atoms in poses:
            ph,ring=classify_pharmacophore(t,atoms)
            cen=pose_centroid(atoms); d=np.linalg.norm(cen-ref["centroid"])
            pocket=float(np.clip(1-(d-4)/8,0,1)); tani=tanimoto(ref["ph"]["contact_res"],ph["contact_res"])
            comps={"pocket":(pocket,0.35),"tani":(tani,0.30)}
            if ref["ph"]["saltbridge"] is not None:
                sb=1.0 if ph["saltbridge"]==ref["ph"]["saltbridge"] else (0.5 if ph["saltbridge"] else 0.0); comps["sb"]=(sb,0.20)
            if ref["ph"]["pistack"] is not None:
                pi=1.0 if ph["pistack"]==ref["ph"]["pistack"] else (0.4 if ph["pistack"] else 0.0); comps["pi"]=(pi,0.15)
            ws=sum(w for _,w in comps.values()); cc=sum(v*w for v,w in comps.values())/ws
            if cc>best_c: best_c=cc; best_atoms=atoms
        entries[lg]=full_coords(best_atoms)
    # key residues: salt bridge + pi stack CA coords
    rec=rec_atom_records(t)
    keyres={}
    for tag,key in [("saltbridge",ref["ph"]["saltbridge"]),("pistack",ref["ph"]["pistack"])]:
        if key:
            ca=[r["xyz"] for r in rec if (r["rn"],r["rs"],r["ch"])==key and r["an"]=="CA"]
            if ca: keyres[f"{key[0]}{key[1]}"]=(tag, ca[0].tolist())
    overlay[t]=dict(poses={k:v.tolist() for k,v in entries.items()}, keyres=keyres,
                    picks=picks, ref_score=ref["score"])
json.dump(overlay, open("handoff/overlay.json","w"))
# also save consistency + scores pivot for heatmap
cpiv.to_csv("handoff/cons_pivot.csv")
piv.to_csv("handoff/score_pivot.csv")
print("overlay data saved for", list(overlay.keys()))
for t in fig_targets:
    print(t, "picks:", overlay[t]["picks"], "keyres:", list(overlay[t]["keyres"].keys()))

import csv
