[tool_use python id=toolu_016P3nBBwM4bJruZBEaNcnsG] {"human_description":"Exporting XYZ geometries and scissile-bond indices","environment":"rdkit","code":"\nimport os, json\nos.makedirs(\"qm\", exist_ok=True)\n\n# 5 linkage variants\nqm_set = [\"Lac-Phe (parent)\",\"Thioamide (C=S)\",\"Reduced amide (CH2-NH)\",\"N-Me amide\",\"1,2,3-triazole\"]\n\ndef scissile(m, name):\n    \"\"\"Return (atomA, atomB) 0-based defining the scissile bond and label.\"\"\"\n    if \"riazole\" in name:\n        # scissile-equivalent = C(alpha)-N(triazole) bond (the bond that replaces amide C-N)\n        patt = Chem.MolFromSmarts(\"[CX4]n1ccnn1\")\n        mm = m.GetSubstructMatches(patt)\n        return (mm[0][0], mm[0][1]), \"Calpha-Ntriazole\"\n    elif \"Reduced\" in name:\n        patt = Chem.MolFromSmarts(\"[CX4][NX3;H1,H2][CX4]\")\n        mm = m.GetSubstructMatches(patt)\n        return (mm[0][0], mm[0][1]), \"CH2-NH\"\n    else:\n        patt = Chem.MolFromSmarts(\"[CX3](=[O,S])[NX3]\")\n        mm = m.GetSubstructMatches(patt)\n        return (mm[0][0], mm[0][2]), \"C(=X)-N\"\n\nmeta = {}\ndef safe(name): return name.replace(\" \",\"_\").replace(\"(\",\"\").replace(\")\",\"\").replace(\"-\",\"_\").replace(\",\",\"\")\nfor name in qm_set:\n    m_full, best, en = mol_objs[name]\n    m = single_conf_mol(m_full, best)\n    (a,b), label = scissile(m, name)\n    fn = f\"qm/{safe(name)}.xyz\"\n    Chem.MolToXYZFile(m, fn, confId=0)\n    # charge is 0 (neutral acid form). xtb 1-based indices:\n    meta[name] = dict(xyz=fn, scissile_1based=[a+1,b+1], label=label,\n                      atomA_sym=m.GetAtomWithIdx(a).GetSymbol(),\n                      atomB_sym=m.GetAtomWithIdx(b).GetSymbol(),\n                      natoms=m.GetNumAtoms())\njson.dump(meta, open(\"qm/meta.json\",\"w\"), indent=2)\nfor n,d in meta.items():\n    print(f\"{n:24s} scissile {d['label']:16s} atoms {d['atomA_sym']}{d['scissile_1based'][0]}-{d['atomB_sym']}{d['scissile_1based'][1]} (natoms {d['natoms']})\")\n"}

