[tool_use python id=toolu_01DPnJ77LkvqqJTidSHsYL5t] {"human_description":"Measuring displacement of SAR-critical pharmacophore groups","environment":"rdkit","code":"\nimport numpy as np\n\ndef pos(m, idx):\n    c = m.GetConformer()\n    p = c.GetAtomPosition(idx)\n    return np.array([p.x, p.y, p.z])\n\ndef match1(m, smarts):\n    patt = Chem.MolFromSmarts(smarts)\n    ms = m.GetSubstructMatches(patt)\n    return ms\n\n# SMARTS for the three key groups (work on mol WITH explicit Hs)\n# carboxylic acid carbon (terminal COOH) — distinguish from amide carbonyl\nCARBOX = \"[CX3](=O)[OX2H1]\"       # acid C, =O, -OH\nCARBOX_O = \"[CX3](=O)[OX1H0-,OX2H1]\"  # both oxygens\n# lactoyl secondary hydroxyl O: C-C(O)-C(=X) ; the aliphatic OH oxygen\nLACTOH = \"[CX4;H1,H2][OX2H1]\"     # aliphatic carbon bearing OH\n# linkage N (amide N, amine N, or triazole substituted N)\ndef get_key_atoms(m):\n    out = {}\n    # carboxyl carbon\n    cb = match1(m, CARBOX)\n    out['carboxyl_C'] = cb[0][0] if cb else None\n    # lactoyl OH oxygen: pick the aliphatic OH (there is one secondary OH near the methyl end)\n    lo = match1(m, LACTOH)\n    out['lactoyl_O'] = lo[0][1] if lo else None\n    return out\n\n# Build reference key atoms (parent)\nref_keys = get_key_atoms(ref)\nref_pos = {k: pos(ref, v) for k,v in ref_keys.items() if v is not None}\n\n# Linkage handling: for amide-type, the carbonyl O and amide N. Compute generically:\n# amide/thioamide carbonyl carbon = C(=O/S)N ; reduced = C-N amine ; triazole = ring N\ndef linkage_atoms(m, name):\n    res = {}\n    if \"riazole\" in name:\n        # triazole: N1 substituted (bearing the Phe alpha C). Acceptor = ring N's\n        patt = Chem.MolFromSmarts(\"c1cn([#6])nn1\")  # 1,2,3-triazole\n        mm = m.GetSubstructMatches(patt)\n        if mm:\n            res['link_N'] = mm[0][2]  # the substituted N\n    elif \"Reduced\" in name:\n        patt = Chem.MolFromSmarts(\"[CX4][NX3;H1,H2][CX4]\")  # secondary amine\n        mm = m.GetSubstructMatches(patt)\n        if mm: res['link_N'] = mm[0][1]\n    else:\n        # amide or thioamide: C(=O)N or C(=S)N\n        patt = Chem.MolFromSmarts(\"[CX3](=[O,S])[NX3]\")\n        mm = m.GetSubstructMatches(patt)\n        if mm:\n            res['link_C'] = mm[0][0]\n            res['link_X'] = mm[0][1]  # =O or =S\n            res['link_N'] = mm[0][2]\n    return res\n\nref_link = linkage_atoms(ref, ref_name)\nref_link_pos = {k: pos(ref, v) for k,v in ref_link.items()}\n\nfidelity = {}\nfor name, prb in aligned_mols.items():\n    ka = get_key_atoms(prb)\n    dev = {}\n    # carboxyl C deviation\n    if ka['carboxyl_C'] is not None:\n        dev['carboxyl_dev'] = float(np.linalg.norm(pos(prb, ka['carboxyl_C']) - ref_pos['carboxyl_C']))\n    if ka['lactoyl_O'] is not None and 'lactoyl_O' in ref_pos:\n        dev['lactoylOH_dev'] = float(np.linalg.norm(pos(prb, ka['lactoyl_O']) - ref_pos['lactoyl_O']))\n    # linkage N deviation vs parent amide N\n    lk = linkage_atoms(prb, name)\n    if 'link_N' in lk and 'link_N' in ref_link_pos:\n        dev['linkageN_dev'] = float(np.linalg.norm(pos(prb, lk['link_N']) - ref_link_pos['link_N']))\n    fidelity[name] = dev\n\nfor n,d in fidelity.items():\n    print(f\"{n:26s} \" + \" \".join(f\"{k}={v:.2f}\" for k,v in d.items()))\nprint(\"\\nref carboxyl_C idx\", ref_keys['carboxyl_C'], \"lactoyl_O idx\", ref_keys['lactoyl_O'], \"link\", ref_link)\n"}

