[tool_use python id=toolu_01MwmCf95opU1aWKvX1qx8Ye] {"human_description":"Parsing Wiberg bond orders and linkage charges","environment":"rdkit","code":"\nimport json, numpy as np\nmeta = json.load(open(\"qm/meta.json\"))\ndef safe(name): return name.replace(\" \",\"_\").replace(\"(\",\"\").replace(\")\",\"\").replace(\"-\",\"_\").replace(\",\",\"\")\n\ndef parse_wbo(path):\n    d={}\n    for line in open(path):\n        p=line.split()\n        if len(p)>=3:\n            i,j,w=int(p[0]),int(p[1]),float(p[2])\n            d[(i,j)]=w; d[(j,i)]=w\n    return d\ndef parse_charges(path):\n    return [float(x) for x in open(path) if x.strip()]\n\nqm_rows=[]\nfor name,d in meta.items():\n    base=safe(name)\n    rd=f\"qm/run_{base}\"\n    wbo=parse_wbo(f\"{rd}/wbo\")\n    chg=parse_charges(f\"{rd}/charges\")\n    a,b=d['scissile_1based']\n    bo=wbo.get((a,b),float('nan'))\n    qA,qB=chg[a-1],chg[b-1]\n    # geometry retention: RMSD of opt vs input heavy atoms\n    qm_rows.append(dict(molecule=name, linkage=d['label'],\n        scissile_atoms=f\"{d['atomA_sym']}{a}-{d['atomB_sym']}{b}\",\n        wiberg_bond_order=round(bo,3),\n        q_atomA=round(qA,3), q_atomB_N=round(qB,3),\n        charge_sep=round(abs(qA-qB),3)))\n\nimport pandas as pd\nqdf=pd.DataFrame(qm_rows)\n# rank by bond order (higher = more covalent/inert scissile bond)\nqdf=qdf.sort_values('wiberg_bond_order',ascending=False).reset_index(drop=True)\nprint(qdf.to_string(index=False))\n"}

